/**
 * MedX grid layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * CSS grid templates for inventory dashboards.
 */
const GRID_TOKENS = Object.freeze({
  primary: { value: "layout-grid-primary", scope: "layout" },
  secondary: { value: "layout-grid-secondary", scope: "layout" },
  muted: { value: "layout-grid-muted", scope: "layout" },
  accent: { value: "layout-grid-accent", scope: "layout" },
  surface: { value: "layout-grid-surface", scope: "layout" },
});

const GRID_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const GRID_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const gridRegistry = new Map();
const GRID_listeners = new Set();
let GRID_seq = 0;

function createGridId(prefix = "medx-layout-grid") {
  GRID_seq += 1;
  return `${prefix}-${GRID_seq}`;
}

function registerGrid(config = {}) {
  const entryId = config.id ?? createGridId();
  const preset = GRID_PRESETS[config.preset ?? "default"] ?? GRID_PRESETS.default;
  const token = GRID_TOKENS[config.token ?? preset.token] ?? GRID_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: GRID_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  gridRegistry.set(entryId, entry);
  notifyGridListeners("register", entry);
  return entry;
}

function updateGrid(id, patch = {}) {
  const entry = gridRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyGridListeners("update", entry);
  return entry;
}

function resolveGrid(id) {
  const entry = gridRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listGridEntries(filter = {}) {
  let items = Array.from(gridRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onGridEvent(listener) {
  GRID_listeners.add(listener);
  return () => GRID_listeners.delete(listener);
}

function notifyGridListeners(type, entry) {
  for (const listener of GRID_listeners) {
    try {
      listener({ type, entry, registrySize: gridRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:grid] listener error", err.message);
    }
  }
}

function getGridMetrics() {
  const items = listGridEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(GRID_TOKENS).length,
    presets: Object.keys(GRID_PRESETS).length,
  };
}

async function runMedxGrid() {
  console.log("[medx:ui:layout:grid] runtime initialized");
  console.log(`[medx:ui:layout:grid] tokens=${Object.keys(GRID_TOKENS).length} presets=${Object.keys(GRID_PRESETS).length}`);

  const events = [];
  onGridEvent((e) => events.push(e.type));

  const domains = Object.keys(GRID_SUPPLY_CHAIN);
  const presets = Object.keys(GRID_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerGrid({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/grid" },
    });
  }

  const first = listGridEntries()[0];
  if (first) updateGrid(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getGridMetrics();
  const resolved = first ? resolveGrid(first.id) : null;

  console.log(`[medx:ui:layout:grid] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:grid] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:grid] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:grid] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:grid] bootstrap complete");
}

module.exports = runMedxGrid;
